def main():
    print("🚀 开始更新道路数据（使用高德预获取真实路网折线）...")
    deleted = TrafficFlow.objects.all().delete()
    print(f"已清空旧数据: {deleted[0]} 条")
    created = 0
    for name, meta in ROAD_META.items():
        path = ROAD_PATHS.get(name)
        if not path:
            print(f"  ⚠️  {name}: 无路径数据，跳过")
            continue
        start = path[0]; end = path[-1]; center = path[len(path)//2]
        TrafficFlow.objects.create(
            road_name=name,
            road_level=meta["level"],
            start_lat=start[0], start_lng=start[1],
            end_lat=end[0], end_lng=end[1],
            center_lat=center[0], center_lng=center[1],
            daily_flow=meta["daily_flow"],
            peak_flow=meta["peak_flow"],
            ev_ratio=meta["ev_ratio"],
            heat_weight=meta["heat_weight"],
            district=meta.get("district", ""),
            path_json=json.dumps(path),
        )
        created += 1
        print(f"  ✅ {name}: {len(path)} 个路径点")
    print(f"\n完成！共创建 {created} 条道路，数据库总数: {TrafficFlow.objects.count()}")

if __name__ == "__main__":
    main()
